let currentSummaryIndex = 0;
let currentSummarySlides = [];

function openResourceDetail(type, id) {
    const resources = resourcesData[type];
    const resource = resources.find(r => r.id === id);

    if (!resource) return;

    const modal = document.getElementById('resourceModal');
    if (!modal) {
        console.error('resourceModal not found');
        return;
    }

    const content = document.getElementById('resourceDetail');

    // 요약 슬라이드 모달 (slides / textbooks / videos / presentations / documents)
    const summaryGenerators = {
        slides: generateSummarySlidesForSlide,
        textbooks: generateSummarySlidesForTextbook,
        videos: generateSummarySlidesForVideo,
        presentations: generateSummarySlidesForPresentation,
        documents: generateSummarySlidesForDocument
    };
    if (summaryGenerators[type]) {
        currentSlideId = resource.id;
        currentSlideTitle = resource.title;
        currentSummarySlides = summaryGenerators[type](resource.id, resource.title);
        currentSummaryIndex = 0;
        showSummarySlide();
        modal.classList.add('show');
        return;
    }

    let html = `
        <h3>${resource.title}</h3>
        <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 20px; margin-bottom: 20px;">
            <div>
                <p><strong>📝 설명:</strong> ${resource.desc}</p>
                <p><strong>🎓 Phase:</strong> <span style="background: #e0f2fe; color: #0066CC; padding: 4px 8px; border-radius: 4px;">${resource.phase}</span></p>
    `;

    if (resource.category) {
        html += `<p><strong>📂 카테고리:</strong> ${resource.category}</p>`;
    }
    if (resource.publisher) {
        html += `<p><strong>📖 출판사:</strong> ${resource.publisher}</p>`;
    }
    if (resource.type) {
        html += `<p><strong>🏷️ 유형:</strong> ${resource.type}</p>`;
    }
    if (resource.duration) {
        html += `<p><strong>⏱️ 소요시간:</strong> ${resource.duration}</p>`;
    }

    html += `</div>
        <div style="background: #f9fafb; padding: 15px; border-radius: 8px; border-left: 4px solid #0066CC;">
            <h4 style="margin-top: 0; color: #0066CC;">📥 액세스</h4>
    `;

    if (type === 'videos' && resource.file.includes('youtube')) {
        html += `
            <p style="margin-bottom: 10px;">이 자료는 YouTube에서 시청할 수 있습니다.</p>
            <a href="${resource.file}" target="_blank" class="btn btn-primary" style="display: inline-block; margin-top: 10px;">🎬 유튜브에서 보기</a>
        `;
    } else {
        html += `
            <p style="margin-bottom: 10px;"><strong>파일:</strong> <code style="background: white; padding: 4px 8px; border-radius: 4px; font-size: 12px;">${resource.file}</code></p>
            <p style="font-size: 13px; color: #666; margin-bottom: 10px;">📂 자료 폴더에서 다운로드 가능</p>
            <button class="btn btn-primary" onclick="downloadResource('${resource.file}')" style="display: inline-block;">📥 다운로드</button>
        `;
    }

    html += `
        </div>
        </div>

        <div style="background: #d1fae5; padding: 15px; border-radius: 8px; margin-bottom: 20px;">
            <h4 style="margin-top: 0; color: #059669;">💡 학습 팁</h4>
            <ul style="margin: 0; padding-left: 20px; color: #059669;">
                <li>이 자료를 공부한 후 진도 페이지에서 학습 기록을 남기세요</li>
                <li>개념정리 페이지에서 핵심 내용을 정리하면 더 효과적입니다</li>
                <li>포럼에서 다른 학습자와 의견을 나누세요</li>
                <li>충분히 학습한 후 퀴즈로 이해도를 확인하세요</li>
            </ul>
        </div>

        <div style="margin-top: 20px; padding-top: 20px; border-top: 1px solid #e5e7eb;">
            <button class="btn btn-secondary" onclick="closeResourceModal()" style="width: 100%;">닫기</button>
        </div>
    `;

    content.innerHTML = html;
    modal.classList.add('show');
}

function showSummarySlide() {
    const modal = document.getElementById('resourceModal');
    const content = document.getElementById('resourceDetail');

    if (!currentSummarySlides || currentSummarySlides.length === 0) return;

    const summary = currentSummarySlides[currentSummaryIndex];
    const progressPercent = ((currentSummaryIndex + 1) / currentSummarySlides.length) * 100;

    // 슬라이드 번호 배경색 (다양한 색상)
    const colors = [
        { bg: '#0066CC', light: '#f0f9ff' },
        { bg: '#10b981', light: '#f0fdf4' },
        { bg: '#f59e0b', light: '#fffbeb' },
        { bg: '#ec4899', light: '#fdf2f8' },
        { bg: '#8b5cf6', light: '#faf5ff' },
        { bg: '#06b6d4', light: '#f0f9fa' },
        { bg: '#6366f1', light: '#f0f4ff' },
        { bg: '#d946ef', light: '#fdf4ff' },
        { bg: '#ea580c', light: '#fef2f0' },
        { bg: '#059669', light: '#f0fdf5' }
    ];
    const slideColor = colors[currentSummaryIndex % colors.length];

    // 요약 슬라이드 목록 생성
    let summaryListHtml = '<div style="display: flex; gap: 8px; flex-wrap: wrap; margin-top: 15px;">';
    for (let i = 0; i < currentSummarySlides.length; i++) {
        const isActive = i === currentSummaryIndex;
        const color = colors[i % colors.length];
        summaryListHtml += `
            <button onclick="jumpToSummarySlide(${i})" style="
                padding: 8px 14px;
                border: 2px solid ${isActive ? color.bg : '#e5e7eb'};
                background: ${isActive ? color.bg : 'white'};
                color: ${isActive ? 'white' : color.bg};
                border-radius: 6px;
                font-size: 12px;
                cursor: pointer;
                font-weight: ${isActive ? '700' : '600'};
                transition: all 0.3s;
            " title="${currentSummarySlides[i].title}">
                ${i + 1}
            </button>
        `;
    }
    summaryListHtml += '</div>';

    // 학습 내용 렌더링
    let contentHtml = '';
    if (summary.content && Array.isArray(summary.content)) {
        contentHtml = '<ul style="margin: 15px 0; padding-left: 20px; color: #1f2937; line-height: 1.8;">';
        summary.content.forEach(item => {
            contentHtml += `<li style="margin-bottom: 12px; font-size: 14px;">${item}</li>`;
        });
        contentHtml += '</ul>';
    }

    // 핵심 포인트 렌더링
    let keyPointsHtml = '';
    if (summary.keyPoints && Array.isArray(summary.keyPoints) && summary.keyPoints.length > 0) {
        keyPointsHtml = '<div style="display: flex; gap: 10px; flex-wrap: wrap; margin-top: 15px;">';
        summary.keyPoints.forEach(point => {
            keyPointsHtml += `
                <span style="
                    background: ${slideColor.light};
                    color: ${slideColor.bg};
                    padding: 6px 12px;
                    border-radius: 20px;
                    font-size: 12px;
                    font-weight: 600;
                    border: 1px solid ${slideColor.bg};
                ">🎯 ${point}</span>
            `;
        });
        keyPointsHtml += '</div>';
    }

    let html = `
        <style>
            .slide-container {
                background: white;
                border-radius: 12px;
                margin-bottom: 20px;
                box-shadow: 0 8px 24px rgba(0, 0, 0, 0.1);
                overflow: hidden;
            }
            .slide-header {
                background: linear-gradient(135deg, ${slideColor.bg} 0%, ${slideColor.light} 100%);
                padding: 40px;
                color: white;
                border-left: 6px solid ${slideColor.bg};
            }
            .slide-number {
                display: inline-block;
                background: rgba(255, 255, 255, 0.3);
                color: white;
                padding: 8px 16px;
                border-radius: 20px;
                font-size: 12px;
                font-weight: 600;
                margin-bottom: 15px;
            }
            .slide-title {
                font-size: 32px;
                font-weight: 700;
                margin: 0 0 10px 0;
                line-height: 1.3;
            }
            .slide-subtitle {
                font-size: 16px;
                opacity: 0.9;
                margin: 0;
                font-weight: 500;
            }
            .slide-body {
                padding: 40px;
                background: white;
            }
            .slide-footer {
                background: ${slideColor.light};
                border-top: 2px solid ${slideColor.bg};
                padding: 20px 40px;
                display: flex;
                justify-content: space-between;
                align-items: center;
            }
        </style>

        <div class="slide-container">
            <div style="background: ${slideColor.bg}; color: white; padding: 15px 40px; font-size: 14px; font-weight: 600;">
                슬라이드${currentSlideId} - ${currentSlideTitle}(${summary.subtitle})
            </div>
            <div class="slide-header">
                <div class="slide-number">슬라이드 ${currentSummaryIndex + 1} / ${currentSummarySlides.length}</div>
                <div class="slide-title">${summary.title}</div>
                ${summary.subtitle ? `<div class="slide-subtitle">${summary.subtitle}</div>` : ''}
            </div>

            <div class="slide-body">
                ${contentHtml}
                ${keyPointsHtml}
            </div>

            <div class="slide-footer">
                <span style="color: ${slideColor.bg}; font-size: 13px; font-weight: 600;">교정학 학습 슬라이드</span>
                <span style="color: #999; font-size: 12px;">${currentSummaryIndex + 1}/${currentSummarySlides.length}</span>
            </div>
        </div>

        <div class="summary-progress">
            <div class="summary-progress-bar" style="width: ${progressPercent}%; background: ${slideColor.bg};"></div>
        </div>

        <div style="display: flex; gap: 10px; margin-bottom: 20px; justify-content: center;">
            ${currentSummaryIndex > 0 ? `<button class="btn btn-secondary" onclick="previousSummarySlide()" style="padding: 10px 20px;">← 이전 슬라이드</button>` : ''}
            <button class="btn btn-primary" onclick="downloadResource('${summary.file}')" style="padding: 10px 20px; background: ${slideColor.bg}; border: none;">📥 PDF 다운로드</button>
            ${currentSummaryIndex < currentSummarySlides.length - 1 ? `<button class="btn btn-secondary" onclick="nextSummarySlide()" style="padding: 10px 20px;">다음 슬라이드 →</button>` : ''}
        </div>
        <div style="margin-top: 20px; padding-top: 20px; border-top: 1px solid #e5e7eb;">
            <button class="btn btn-secondary" onclick="closeResourceModal()" style="width: 100%; padding: 12px;">모달 닫기</button>
        </div>
    `;

    content.innerHTML = html;
    setupSummaryKeyboardNavigation();
}

function jumpToSummarySlide(index) {
    if (index >= 0 && index < currentSummarySlides.length) {
        currentSummaryIndex = index;
        showSummarySlide();
    }
}

function nextSummarySlide() {
    if (currentSummaryIndex < currentSummarySlides.length - 1) {
        currentSummaryIndex++;
        showSummarySlide();
    }
}

function previousSummarySlide() {
    if (currentSummaryIndex > 0) {
        currentSummaryIndex--;
        showSummarySlide();
    }
}

function setupSummaryKeyboardNavigation() {
    document.removeEventListener('keydown', handleSummaryKeydown);
    document.addEventListener('keydown', handleSummaryKeydown);
}

function handleSummaryKeydown(event) {
    if (event.key === 'ArrowRight') {
        nextSummarySlide();
    } else if (event.key === 'ArrowLeft') {
        previousSummarySlide();
    }
}

function removeSummaryKeyboardNavigation() {
    document.removeEventListener('keydown', handleSummaryKeydown);
}

function closeResourceModal() {
    const modal = document.getElementById('resourceModal');
    if (modal) {
        modal.classList.remove('show');
    }
    removeSummaryKeyboardNavigation();
    currentSummarySlides = [];
    currentSummaryIndex = 0;
}

function downloadResource(filePath) {
    alert(`📥 파일: ${filePath}\n\n자료 폴더에서 다운로드해주세요.\n(실제 배포 시 직접 다운로드 기능 추가 예정)`);
}

document.addEventListener('DOMContentLoaded', () => {
    // URL 파라미터 처리 (README.md에서 직접 이동할 때)
    const params = new URLSearchParams(window.location.search);
    const typeParam = params.get('type');
    const idParam = params.get('id');

    if (typeParam && idParam) {
        localStorage.setItem('targetTab', typeParam);
        localStorage.setItem('targetSlide', parseInt(idParam));
        window.history.replaceState({}, document.title, window.location.pathname);
    }

    // 모달 HTML이 없으면 추가
    if (!document.getElementById('resourceModal')) {
        const modalHTML = `
            <div id="resourceModal" class="resource-modal">
                <div class="resource-modal-content">
                    <span class="close-btn" onclick="closeResourceModal()" style="float: right; font-size: 24px; cursor: pointer; color: #999;">&times;</span>
                    <div id="resourceDetail"></div>
                </div>
            </div>
        `;
        document.body.insertAdjacentHTML('beforeend', modalHTML);
    }

    // 각 탭의 resource-grid 생성
    const slidesGrid = document.querySelector('#slides .resource-grid');
    if (slidesGrid && slidesGrid.children.length === 0) {
        let html = '';
        resourcesData.slides.forEach(slide => {
            html += `
                <div class="resource-card" onclick="openResourceDetail('slides', ${slide.id})">
                    <h4>📸 ${slide.title}</h4>
                    <p>${slide.desc}</p>
                    <span class="resource-badge">${slide.phase}</span>
                </div>
            `;
        });
        slidesGrid.innerHTML = html;
    }

    const textbooksGrid = document.querySelector('#textbooks .resource-grid');
    if (textbooksGrid && textbooksGrid.children.length === 0) {
        let html = '';
        resourcesData.textbooks.forEach(book => {
            html += `
                <div class="resource-card" onclick="openResourceDetail('textbooks', ${book.id})">
                    <h4>📖 ${book.title}</h4>
                    <p>${book.desc}</p>
                    <span class="resource-badge">${book.phase}</span>
                </div>
            `;
        });
        textbooksGrid.innerHTML = html;
    }

    const videosGrid = document.querySelector('#videos .resource-grid');
    if (videosGrid && videosGrid.children.length === 0) {
        let html = '';
        resourcesData.videos.forEach(video => {
            html += `
                <div class="resource-card" onclick="openResourceDetail('videos', ${video.id})">
                    <h4>🎬 ${video.title}</h4>
                    <p>${video.desc}</p>
                    <span class="resource-badge">${video.phase}</span>
                </div>
            `;
        });
        videosGrid.innerHTML = html;
    }

    const presentationsGrid = document.querySelector('#presentations .resource-grid');
    if (presentationsGrid && presentationsGrid.children.length === 0) {
        let html = '';
        resourcesData.presentations.forEach(pres => {
            html += `
                <div class="resource-card" onclick="openResourceDetail('presentations', ${pres.id})">
                    <h4>📊 ${pres.title}</h4>
                    <p>${pres.desc}</p>
                    <span class="resource-badge">${pres.phase}</span>
                </div>
            `;
        });
        presentationsGrid.innerHTML = html;
    }

    const documentsDiv = document.querySelector('#documents');
    const existingGrid = documentsDiv.querySelector('.resource-grid');
    if (!existingGrid) {
        let html = '<div class="resource-grid">';
        resourcesData.documents.forEach(doc => {
            html += `
                <div class="resource-card" onclick="openResourceDetail('documents', ${doc.id})">
                    <h4>📄 ${doc.title}</h4>
                    <p>${doc.desc}</p>
                    <span class="resource-badge">${doc.phase}</span>
                </div>
            `;
        });
        html += '</div>';
        const noteDiv = documentsDiv.querySelector('div[style*="background: #d1fae5"]');
        if (noteDiv) {
            noteDiv.insertAdjacentHTML('afterend', html);
        }
    }

    // 모달 외부 클릭 시 닫기
    const modal = document.getElementById('resourceModal');
    if (modal) {
        modal.addEventListener('click', (e) => {
            if (e.target === modal) {
                closeResourceModal();
            }
        });
        // ESC 키로 모달 닫기
        document.addEventListener('keydown', (e) => {
            if (e.key === 'Escape' && modal.classList.contains('show')) {
                closeResourceModal();
            }
        });
    }
});
